265→// getFileChanges returns the current file changes from git status.
266→// Returns (modifiedFiles, untrackedFiles, deletedFiles, stagedFiles, error)
267→func getFileChanges() ([]string, []string, []string, []string, error) {
268→	repo, err := openRepository()
269→	if err != nil {
270→		return nil, nil, nil, nil, err
271→	}
272→
273→	worktree, err := repo.Worktree()
274→	if err != nil {
275→		return nil, nil, nil, nil, fmt.Errorf("getting worktree: %w", err)
276→	}
277→
278→	status, err := worktree.Status()
279→	if err != nil {
280→		return nil, nil, nil, nil, fmt.Errorf("getting status: %w", err)
281→	}
282→
283→	var modifiedFiles, untrackedFiles, deletedFiles, stagedFiles []string
284→
285→	for file, st := range status {
286→		// Skip .entire directory
287→		if paths.IsInfrastructurePath(file) {
288→			continue
289→		}
290→
291→		// Check staging area first
292→		switch st.Staging {
293→		case git.Added, git.Modified:
294→			stagedFiles = append(stagedFiles, file)
295→			continue
296→		case git.Deleted:
297→			deletedFiles = append(deletedFiles, file)
298→			continue
299→		case git.Unmodified, git.Renamed, git.Copied, git.UpdatedButUnmerged, git.Untracked:
300→			// Fall through to check worktree status
301→		}
302→
303→		// Check worktree status
304→		switch st.Worktree {
305→		case git.Modified:
306→			modifiedFiles = append(modifiedFiles, file)
307→		case git.Untracked:
308→			untrackedFiles = append(untrackedFiles, file)
309→		case git.Deleted:
310→			deletedFiles = append(deletedFiles, file)
311→		case git.Unmodified, git.Added, git.Renamed, git.Copied, git.UpdatedButUnmerged:
312→			// No action needed
313→		}
314→	}
315→
316→	// Sort for consistent output
317→	sort.Strings(modifiedFiles)
318→	sort.Strings(untrackedFiles)
319→	sort.Strings(deletedFiles)
320→	sort.Strings(stagedFiles)
321→
322→	return modifiedFiles, untrackedFiles, deletedFiles, stagedFiles, nil
323→}
