325→// findTranscriptForSession attempts to find the transcript file for a session.
326→// Returns the path if found, empty string if not found, or error on failure.
327→func findTranscriptForSession(sessionID string) (string, error) {
328→	// Try to get agent type from session state
329→	sessionState, err := strategy.LoadSessionState(sessionID)
330→	if err != nil {
331→		return "", fmt.Errorf("failed to load session state: %w", err)
332→	}
333→
334→	var ag agent.Agent
335→	if sessionState != nil && sessionState.AgentType != "" {
336→		ag, err = agent.GetByAgentType(sessionState.AgentType)
337→		if err != nil {
