		t.Fatalf("Failed to write local settings file: %v", err)
	}

	settings, err := LoadEntireSettings()
	if err != nil {
		t.Fatalf("LoadEntireSettings() error = %v", err)
	}
	if settings.Enabled {
		t.Error("Enabled should be false from local override")
	}
