	if settings.Strategy != strategy.StrategyNameManualCommit {
		t.Errorf("Strategy should be migrated to 'manual-commit' from auto-commit, got %q", settings.Strategy)
	}
	if !settings.Enabled {
		t.Error("Enabled should default to true")
